// Pull article markdown out of Anthropic's response shape
const response = $input.first().json;
let article = response.content && response.content[0] && response.content[0].text;

if (!article) {
  throw new Error('No article text in Anthropic response. Full response: ' + JSON.stringify(response).slice(0, 500));
}

// Defensive sanitizers
// 1. Strip leading ```markdown / ``` fences and trailing ``` fences if the LLM wrapped the file
article = article.trim();
if (article.startsWith('```markdown') || article.startsWith('```md')) {
  article = article.replace(/^```(markdown|md)\n?/, '').replace(/\n?```\s*$/, '').trim();
} else if (article.startsWith('```')) {
  article = article.replace(/^```\n?/, '').replace(/\n?```\s*$/, '').trim();
}

// 2. If the LLM wrapped JUST the frontmatter in fences (the common bug),
//    strip the leading ``` and the closing ``` immediately after the frontmatter end
// Pattern: ```\n---\n...frontmatter...\n---\n```\n\nbody...
const fmFenceRe = /^```\s*\n(---\n[\s\S]*?\n---)\n```\s*\n/;
if (fmFenceRe.test(article)) {
  article = article.replace(fmFenceRe, '$1\n\n');
}

// 3. Validate frontmatter exists at start
if (!article.startsWith('---')) {
  throw new Error('Article does not start with frontmatter (---). First 200 chars: ' + article.slice(0, 200));
}

// Carry slug forward from the earlier Build prompt node
const slug = $('Build prompt').first().json.slug;

return [{
  json: {
    slug,
    article,
    filePath: `app/content/blog/${slug}.md`,
    commitMessage: `Auto-generated pillar article: ${slug}`
  }
}];
